/**
 *
 * @param geoMap
 * @return {{scale: number, translate: [number, number]}}
 * @private
 */
export function __getBaseProjectionTransform(geoMap) {
    let baseProjection = (geoMap.baseProjection = geoMap.baseProjection = geoMap.getProjection(geoMap.geo.renderedLayer));
    return {
        scale: baseProjection.scale(),
        translate: baseProjection.translate()
    };
}
